+export function applyWithScopedRuleIgnores(text: string, ruleAlias: string, knownRuleAliases: string[], apply: (text: string) => string): string {
+  const lines = text.split('\
');
+  const protectedLines = new Set<number>();
+  const lineDisables = new Map<number, DisableScope[]>();
+  const scopes: DisableScope[] = [];
+  const aliases = new Set(knownRuleAliases.map((alias) => alias.toLowerCase()));
+  const normalizedRuleAlias = ruleAlias.toLowerCase();
+  const ignoredContext = getIgnoredContextLines(lines);
+
+  for (let lineIndex = 0; lineIndex < lines.length; lineIndex++) {
+    if (ignoredContext.has(lineIndex)) {
+      continue;
+    }
+
+    const marker = parseMarker(lines[lineIndex]);
+    if (!marker) {
+      if (scopes.some((scope) => scopeDisablesRule(scope, normalizedRuleAlias)) ||
+          (lineDisables.get(lineIndex) ?? []).some((scope) => scopeDisablesRule(scope, normalizedRuleAlias))) {
+        protectedLines.add(lineIndex);
+      }
+      continue;
+    }
+
+    // Markers themselves are always left byte-for-byte unchanged.
+    protectedLines.add(lineIndex);
+    const parsedRules = normalizeRuleList(marker.ruleList, aliases);
+
+    if (marker.command === 'disable') {
+      const scope = createScope(marker.ruleList === undefined, parsedRules);
+      if (scope) {
+        scopes.push(scope);
+      }
+    } else if (marker.command === 'enable') {
+      if (marker.ruleList === undefined) {
+        scopes.pop();
+      } else {
+        for (const alias of parsedRules) {
+          closeNearestScopeForRule(scopes, alias);
+        }
+      }
+    } else {
+      const scope = createScope(marker.ruleList === undefined, parsedRules);
+      const requestedLineCount = marker.command === 'next-line' ? 1 : parsePositiveInteger(marker.lineCount);
+      if (scope && requestedLineCount !== null) {
+        const endLine = Math.min(lines.length - 1, lineIndex + requestedLineCount);
+        for (let targetLine = lineIndex + 1; targetLine <= endLine; targetLine++) {
+          const targetScopes = lineDisables.get(targetLine) ?? [];
+          targetScopes.push(scope);
+          lineDisables.set(targetLine, targetScopes);
+        }
+      }
+    }
+  }
+
+  const replacements: string[] = [];
+  const protectedText = lines.map((line, index) => {
+    if (!protectedLines.has(index)) {
+      return line;
+    }
+
+    const placeholder = `SCOPEDLINTERIGNOREPLACEHOLDER${replacements.length}X`;
+    replacements.push(line);
+    return placeholder;
+  }).join('\
');
+
+  let result = apply(protectedText);
+  replacements.forEach((line, index) => {
+    result = result.replace(new RegExp(`SCOPEDLINTERIGNOREPLACEHOLDER${index}X`, 'i'), line);
+  });
