+}
+
+function parseMarker(line: string): ParsedMarker | null {
+  const match = line.match(markerRegex);
+  if (!match) {
+    return null;
+  }
+
+  const markerText = match[1] ?? match[5];
+  const lineCount = match[2] ?? match[6];
+  const ruleList = match[3] ?? match[4] ?? match[7] ?? match[8] ?? match[9];
+  if (markerText.startsWith('disable-next-n-lines:')) {
+    return {command: 'next-n-lines', lineCount, ruleList};
+  } else if (markerText.startsWith('disable-next-line')) {
+    return {command: 'next-line', ruleList};
+  } else if (markerText.startsWith('disable')) {
+    return {command: 'disable', ruleList};
+  }
+
+  return {command: 'enable', ruleList};
+}
+
+function normalizeRuleList(ruleList: string | undefined, knownAliases: Set<string>): Set<string> {
+  if (ruleList === undefined) {
+    return new Set();
+  }
+
+  return new Set(ruleList.split(',').map((alias) => alias.trim().toLowerCase()).filter((alias) => alias !== '' && knownAliases.has(alias)));
+}
+
+function createScope(disablesAll: boolean, disabledRules: Set<string>): DisableScope | null {
+  if (!disablesAll && disabledRules.size === 0) {
+    return null;
+  }
+
+  return {disablesAll, disabledRules, enabledRules: new Set()};
+}
+
+function scopeDisablesRule(scope: DisableScope, ruleAlias: string): boolean {
+  return scope.disablesAll ? !scope.enabledRules.has(ruleAlias) : scope.disabledRules.has(ruleAlias);
+}
+
+function closeNearestScopeForRule(scopes: DisableScope[], ruleAlias: string): void {
+  for (let index = scopes.length - 1; index >= 0; index--) {
+    const scope = scopes[index];
+    if (!scopeDisablesRule(scope, ruleAlias)) {
+      continue;
+    }
+
+    if (scope.disablesAll) {
+      scope.enabledRules.add(ruleAlias);
+    } else {
+      scope.disabledRules.delete(ruleAlias);
+      if (scope.disabledRules.size === 0) {
+        scopes.splice(index, 1);
+      }
+    }
+    return;
+  }
+}
