+  let inYaml = lines[0]?.trim() === '---';
+  let fencedCodeMarker: string | null = null;
+  let mathDelimiter: string | null = null;
+
+  for (let index = 0; index < lines.length; index++) {
+    const line = lines[index];
+    if (inYaml) {
+      ignored.add(index);
+      if (index > 0 && /^(---|\\.\\.\\.)[\	 ]*$/.test(line)) {
+        inYaml = false;
+      }
