+    if (fencedCodeMarker) {
+      ignored.add(index);
+      if (new RegExp(`^[\\\	 ]{0,3}${fencedCodeMarker[0]}{${fencedCodeMarker.length},}[\\\	 ]*$`).test(line)) {
+        fencedCodeMarker = null;
+      }
+      continue;
+    }
+
+    const fence = line.match(/^[\	 ]{0,3}(`{3,}|~{3,})/);
+    if (fence) {
+      ignored.add(index);
+      fencedCodeMarker = fence[1];
+      continue;
+    }
+
+    if (mathDelimiter) {
+      ignored.add(index);
+      if (new RegExp(`^[\\\	 ]*${mathDelimiter}[\\\	 ]*$`).test(line)) {
+        mathDelimiter = null;
+      }
+      continue;
+    }
+
+    const math = line.match(/^[\	 ]*(\\${2,})[\	 ]*(?:[^$].*)?$/);
