function parseTextToAST(text: string): Root {
  const textHash = hashString53Bit(text);
  if (LRU.has(textHash)) {
    return LRU.get(textHash) as Root;
  }

  // @ts-expect-error for some reason an overload is missing
  const ast = fromMarkdown(text, {
